INSERT INTO questions (subject, topic, difficulty, question_text, choices, correct_answer, explanation, exam_type) VALUES
('General Education','English','easy','Which sentence has correct subject-verb agreement?','[{"key": "A", "text": "She don''t know the answer."}, {"key": "B", "text": "She doesn''t know the answer."}, {"key": "C", "text": "She don''t knows the answer."}, {"key": "D", "text": "She do not knows the answer."}]','B','The correct answer is B. She doesn''t know the answer..','elementary'),
('General Education','English','easy','The word ''verbose'' most nearly means:','[{"key": "A", "text": "Brief and concise"}, {"key": "B", "text": "Using more words than necessary"}, {"key": "C", "text": "Silent and reserved"}, {"key": "D", "text": "Loud and noisy"}]','B','The correct answer is B. Using more words than necessary.','elementary'),
('General Education','English','easy','''Life is a journey'' is an example of:','[{"key": "A", "text": "Simile"}, {"key": "B", "text": "Personification"}, {"key": "C", "text": "Metaphor"}, {"key": "D", "text": "Hyperbole"}]','C','The correct answer is C. Metaphor.','elementary'),
('General Education','English','easy','The main idea of a paragraph is best found in the:','[{"key": "A", "text": "Last sentence"}, {"key": "B", "text": "Middle sentence"}, {"key": "C", "text": "Topic sentence"}, {"key": "D", "text": "Supporting details"}]','C','The correct answer is C. Topic sentence.','elementary'),
('General Education','English','easy','Which word means the OPPOSITE of ''transparent''?','[{"key": "A", "text": "Clear"}, {"key": "B", "text": "Obvious"}, {"key": "C", "text": "Opaque"}, {"key": "D", "text": "Visible"}]','C','The correct answer is C. Opaque.','elementary'),
('General Education','English','easy','''The flowers danced in the breeze'' uses which literary device?','[{"key": "A", "text": "Simile"}, {"key": "B", "text": "Alliteration"}, {"key": "C", "text": "Personification"}, {"key": "D", "text": "Metaphor"}]','C','The correct answer is C. Personification.','elementary'),
('General Education','English','easy','Choose the correctly spelled word:','[{"key": "A", "text": "Recieve"}, {"key": "B", "text": "Accommodate"}, {"key": "C", "text": "Accomodate"}, {"key": "D", "text": "Acommodate"}]','B','The correct answer is B. Accommodate.','elementary'),
('General Education','English','easy','A narrative essay primarily aims to:','[{"key": "A", "text": "Persuade the reader"}, {"key": "B", "text": "Tell a story or recount events"}, {"key": "C", "text": "Explain a process"}, {"key": "D", "text": "Define key terms"}]','B','The correct answer is B. Tell a story or recount events.','elementary'),
